SELECT location_id, COUNT(part_id) AS part_count
FROM part_inventory
GROUP BY location_id;

SELECT SUM(quantity) AS total_quantity
FROM part_inventory
WHERE part_id = 1;

SELECT SUM(quantity_used) AS total_quantity_used
FROM part_usage
WHERE part_id = 1;

SELECT COUNT(part_id) AS parts_below_reorder
FROM part_inventory
WHERE quantity < reorder_level;

SELECT part_id
FROM part_inventory
WHERE quantity < reorder_level;

SELECT part_type_name
FROM part_types
WHERE category = 'Electrical';

SELECT SUM(quantity_ordered) AS total_quantity_ordered
FROM part_orders
WHERE part_id = 1;

SELECT part_code, part_description
FROM parts
ORDER BY part_code ASC;
